def add_row(panels: list[dict], panel_id: int, y: int, title: str, specs: list[dict]) -> tuple[int, int, list[dict]]:
    panels.append(row_panel(panel_id, title, y))
    panel_id += 1
    y += 1
    x = 0
    records: list[dict] = []
    for spec in specs:
        width = spec.get("width", 8)
        height = spec.get("height", 8)
        if x + width > 24:
            x = 0
            y += height
        panels.append(timeseries_panel(panel_id, spec["title"], spec["description"], spec["targets"], x, y, spec.get("unit", "none"), width=width, height=height))
        records.append({"title": spec["title"], "unit": spec.get("unit", "none"), "metrics": spec.get("metrics", []), "description": spec["description"]})
        panel_id += 1
        x += width
    y += (specs[-1].get("height", 8) if specs else 0) + 1
    return panel_id, y, records


def overview(panel_id: int, y: int) -> tuple[list[dict], int, int, dict]:
    panels = [row_panel(panel_id, "Overview", y)]
    panel_id += 1
    y += 1
    stats = [
        ("MongoDB Up", 'max(mongodb_up{instance="$instance"})', "Shows whether the selected MongoDB target is scrapeable from Prometheus.", "none", ["mongodb_up"]),
        ("Uptime", 'max(mongodb_ss_uptime{instance="$instance"})', "Server uptime in seconds since the mongod process started.", "s", ["mongodb_ss_uptime"]),
        ("Current Connections", 'max(mongodb_ss_connections{instance="$instance",conn_type="current"})', "Current client connections accepted by MongoDB.", "short", ["mongodb_ss_connections{conn_type=\"current\"}"]),
        ("Connections Used %", '100 * max(mongodb_ss_connections{instance="$instance",conn_type="current"}) / clamp_min(max(mongodb_ss_connections{instance="$instance",conn_type="current"}) + max(mongodb_ss_connections{instance="$instance",conn_type="available"}), 1)', "Approximate connection pool utilization derived from current and available connection slots.", "percent", ["mongodb_ss_connections{conn_type=\"current\"}", "mongodb_ss_connections{conn_type=\"available\"}"]),
        ("WT Cache Used %", '100 * max(mongodb_ss_wt_cache_bytes_currently_in_the_cache{instance="$instance"}) / clamp_min(max(mongodb_ss_wt_cache_maximum_bytes_configured{instance="$instance"}), 1)', "Percent of WiredTiger cache currently in use. Sustained high values can precede eviction pressure and stalls.", "percent", ["mongodb_ss_wt_cache_bytes_currently_in_the_cache", "mongodb_ss_wt_cache_maximum_bytes_configured"]),
        ("Max Scrape Time", 'max(collector_scrape_time_ms{instance="$instance"})', "Maximum exporter collector scrape time in milliseconds. Useful to spot exporter overhead or stalled collectors.", "ms", ["collector_scrape_time_ms"]),
    ]
    records = {"title": "Overview", "stat_panels": [], "timeseries_panels": []}
    for index, (title, expr, description, unit, metrics) in enumerate(stats):
        panels.append(stat_panel(panel_id + index, title, description, expr, index * 4, y, unit))
        records["stat_panels"].append({"title": title, "unit": unit, "metrics": metrics, "description": description})
    panel_id += len(stats)
    y += 4
    overview_specs = [
        {"title": "Opcounters - Ops/sec", "description": "Per-second MongoDB operation rate split by legacy operation type. Useful for seeing whether load is read-heavy, write-heavy, or command-heavy.", "targets": [target('sum by (legacy_op_type) (rate(mongodb_ss_opcounters{instance="$instance"}[$__rate_interval]))', 0, "{{legacy_op_type}}")], "unit": "ops", "metrics": ["mongodb_ss_opcounters"]},
        {"title": "Average Operation Latency - ms", "description": "Average command, read, write, and transaction latency derived from cumulative opLatencies counters.", "targets": [target('rate(mongodb_ss_opLatencies_latency{instance="$instance",op_type="commands"}[$__rate_interval]) / clamp_min(rate(mongodb_ss_opLatencies_ops{instance="$instance",op_type="commands"}[$__rate_interval]), 1) / 1000', 0, "commands"), target('rate(mongodb_ss_opLatencies_latency{instance="$instance",op_type="reads"}[$__rate_interval]) / clamp_min(rate(mongodb_ss_opLatencies_ops{instance="$instance",op_type="reads"}[$__rate_interval]), 1) / 1000', 1, "reads"), target('rate(mongodb_ss_opLatencies_latency{instance="$instance",op_type="writes"}[$__rate_interval]) / clamp_min(rate(mongodb_ss_opLatencies_ops{instance="$instance",op_type="writes"}[$__rate_interval]), 1) / 1000', 2, "writes"), target('rate(mongodb_ss_opLatencies_latency{instance="$instance",op_type="transactions"}[$__rate_interval]) / clamp_min(rate(mongodb_ss_opLatencies_ops{instance="$instance",op_type="transactions"}[$__rate_interval]), 1) / 1000', 3, "transactions")], "unit": "ms", "metrics": ["mongodb_ss_opLatencies_latency", "mongodb_ss_opLatencies_ops"]},
        {"title": "Slow Query Rate - Queries/sec", "description": "Per-second slow query rate by database using profiler-derived counters. Spikes here often accompany user-visible slowness.", "targets": [target('sum by (database) (rate(mongodb_profile_slow_query_count{instance="$instance"}[$__rate_interval]))', 0, "{{database}}")], "unit": "ops", "metrics": ["mongodb_profile_slow_query_count"]},
    ]
    for index, spec in enumerate(overview_specs):
        panels.append(timeseries_panel(panel_id + index, spec["title"], spec["description"], spec["targets"], index * 8, y, spec["unit"]))
        records["timeseries_panels"].append({"title": spec["title"], "unit": spec["unit"], "metrics": spec["metrics"], "description": spec["description"]})
    return panels, panel_id + len(overview_specs), y + 9, records


