            {"title": "Host Memory - Bytes", "description": "Host free, available, and swap-free memory converted from kilobytes to bytes. Useful when MongoDB pressure is actually OS memory pressure.", "targets": [target('mongodb_sys_memory_MemAvailable_kb{instance="$instance"} * 1024', 0, "mem available"), target('mongodb_sys_memory_MemFree_kb{instance="$instance"} * 1024', 1, "mem free"), target('mongodb_sys_memory_SwapFree_kb{instance="$instance"} * 1024', 2, "swap free")], "unit": "bytes", "metrics": ["mongodb_sys_memory_MemAvailable_kb", "mongodb_sys_memory_MemFree_kb", "mongodb_sys_memory_SwapFree_kb"]},
            {"title": "Pressure Stall Time - Microseconds/sec", "description": "Per-second CPU, IO, and memory pressure stall time. Rising IO pressure often aligns with storage bottlenecks or checkpoint pressure.", "targets": [target(f'rate(mongodb_ss_extra_info_pressure_cpu_some_totalMicros{{instance="$instance"}}[{RATE_INTERVAL}])', 0, "cpu some"), target(f'rate(mongodb_ss_extra_info_pressure_io_some_totalMicros{{instance="$instance"}}[{RATE_INTERVAL}])', 1, "io some"), target(f'rate(mongodb_ss_extra_info_pressure_memory_some_totalMicros{{instance="$instance"}}[{RATE_INTERVAL}])', 2, "memory some")], "unit": "µs", "metrics": ["mongodb_ss_extra_info_pressure_cpu_some_totalMicros", "mongodb_ss_extra_info_pressure_io_some_totalMicros", "mongodb_ss_extra_info_pressure_memory_some_totalMicros"]},
